import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Maximize2, Minimize2 } from 'lucide-react';
import Section from './components/Section';
import ContactSection from './components/ContactSection';
import ExpertiseSection from './components/ExpertiseSection';
import Layout from './components/Layout';
import { sections, type Language } from './constants/sections';

export default function LandingPage() {
  const [activeSection, setActiveSection] = useState(0);
  const [language, setLanguage] = useState<Language>('mk');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  const currentSections = sections[language];

  useEffect(() => {
    const observerOptions = {
      root: containerRef.current,
      threshold: 0.5,
    };

    const observerCallback = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const index = sectionRefs.current.findIndex((ref) => ref === entry.target);
          if (index !== -1) {
            setActiveSection(index);
          }
        }
      });
    };

    const observer = new IntersectionObserver(observerCallback, observerOptions);
    sectionRefs.current.forEach((ref) => { if (ref) observer.observe(ref); });

    // Listen for fullscreen changes to sync UI state
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);

    return () => { 
      sectionRefs.current.forEach((ref) => { if (ref) observer.unobserve(ref); });
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, [language]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleNavClick = (index: number) => {
    const target = sectionRefs.current[index];
    if (target && containerRef.current) {
      containerRef.current.scrollTo({
        top: target.offsetTop,
        behavior: 'smooth'
      });
    }
  };

  const isAtTop = activeSection === 0;

  return (
    <Layout>
      <motion.header 
        initial={false}
        animate={{
          backgroundColor: isAtTop ? 'rgba(3, 3, 3, 0)' : 'rgba(3, 3, 3, 0.85)',
          backdropFilter: isAtTop ? 'blur(0px)' : 'blur(20px)',
          borderBottomColor: isAtTop ? 'rgba(255, 255, 255, 0)' : 'rgba(255, 255, 255, 0.05)',
        }}
        className="fixed top-0 left-0 right-0 z-50 px-6 py-3 md:px-16 md:py-4 flex justify-between items-center transition-all duration-700 border-b"
      >
        <div className="flex-1 flex justify-start">
          <motion.button
            whileHover={{ scale: 1.05, backgroundColor: 'rgba(255,255,255,0.05)' }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setLanguage(l => l === 'mk' ? 'en' : 'mk')}
            className="px-3 py-1.5 text-[9px] font-black uppercase tracking-[0.2em] text-white/70 border border-white/10 rounded-full hover:text-white transition-all font-mono"
          >
            {language === 'mk' ? 'EN' : 'MK'}
          </motion.button>
        </div>

        <motion.div 
          animate={{ scale: isAtTop ? 1 : 0.9 }}
          className="flex-none text-center cursor-default"
        >
          <span className="text-lg md:text-2xl font-heading font-black tracking-tighter text-white uppercase">
            M&M <span className="text-primary">Media</span>
          </span>
        </motion.div>

        <div className="flex-1 flex justify-end">
          <motion.button
            whileHover={{ scale: 1.05, backgroundColor: 'rgba(255,255,255,0.05)' }}
            whileTap={{ scale: 0.95 }}
            onClick={toggleFullscreen}
            className="p-2 text-white/60 hover:text-white border border-white/10 rounded-full transition-all flex items-center gap-2 group"
            title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
          >
            <span className="hidden md:inline font-mono text-[9px] font-bold tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
              {isFullscreen ? 'EXIT_FS' : 'FULL_SCREEN'}
            </span>
            {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
          </motion.button>
        </div>
      </motion.header>

      {/* Navigation Indicators */}
      <div className="fixed right-6 md:right-12 top-1/2 -translate-y-1/2 flex flex-col gap-7 z-50">
        {currentSections.map((_, index) => (
          <button
            key={index}
            onClick={() => handleNavClick(index)}
            className="group relative flex items-center justify-center p-2"
          >
            <motion.div
              animate={{
                scale: index === activeSection ? 1.8 : 1,
                backgroundColor: index === activeSection ? '#3b82f6' : 'rgba(255,255,255,0.15)',
                boxShadow: index === activeSection ? '0 0 15px rgba(59,130,246,0.6)' : '0 0 0px transparent'
              }}
              className="w-1.5 h-1.5 rounded-full transition-all duration-500"
            />
          </button>
        ))}
      </div>

      <div ref={containerRef} className="snap-container no-scrollbar">
        {currentSections.map((section, index) => (
          <div 
            key={`${section.id}-${language}`} 
            ref={(el) => { sectionRefs.current[index] = el; }}
            className="snap-child"
          >
            {section.id === 'contact' ? (
              <ContactSection isActive={index === activeSection} language={language} />
            ) : section.id === 'expertise' ? (
              <ExpertiseSection 
                isActive={index === activeSection} 
                language={language} 
              />
            ) : (
              <Section {...section} isActive={index === activeSection} />
            )}
          </div>
        ))}
      </div>
    </Layout>
  );
}

