// Нова компонента за дигитална анимација
const TechNodeNetwork: React.FC = () => {
  const nodes = useMemo(() => Array.from({ length: 15 }).map((_, i) => ({
    id: i,
    initialX: Math.random() * 100,
    initialY: Math.random() * 100,
    moveX: (Math.random() - 0.5) * 20,
    moveY: (Math.random() - 0.5) * 20,
    duration: Math.random() * 10 + 10,
    size: Math.random() * 2 + 1,
  })), []);

  return (
    <div className="absolute inset-0 z-[2] overflow-hidden pointer-events-none">
      {/* Мрежа од подвижни точки (nodes) */}
      {nodes.map((node) => (
        <motion.div
          key={node.id}
          className="absolute rounded-full bg-primary/20 blur-[1px]"
          style={{
            width: node.size,
            height: node.size,
            left: `${node.initialX}%`,
            top: `${node.initialY}%`,
          }}
          animate={{
            x: [`0px`, `${node.moveX}px`, `0px`],
            y: [`0px`, `${node.moveY}px`, `0px`],
            opacity: [0.1, 0.4, 0.1],
          }}
          transition={{
            duration: node.duration,
            repeat: Infinity,
            ease: "easeInOut",
          }}
        />
      ))}

      {/* Анимирани линии на податоци (Data streams) */}
      <div className="absolute inset-0 opacity-20">
        {[...Array(5)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute h-[1px] bg-gradient-to-r from-transparent via-primary/40 to-transparent w-full"
            style={{ top: `${20 * (i + 1)}%`, left: 0 }}
            animate={{
              x: ['-100%', '100%'],
              opacity: [0, 1, 0]
            }}
            transition={{
              duration: 8 + i * 2,
              repeat: Infinity,
              ease: "linear",
              delay: i * 1.5
            }}
          />
        ))}
      </div>

      {/* Скенирачки ефект */}
      <motion.div
        className="absolute top-0 left-0 w-full h-[30vh] bg-gradient-to-b from-primary/5 to-transparent pointer-events-none"
        animate={{
          y: ['-100%', '300%'],
        }}
        transition={{
          duration: 12,
          repeat: Infinity,
          ease: "linear",
        }}
      />
    </div>
  );
};

